void KeyQueue::push(const KeyEvent& ev) {
    std::lock_guard<std::mutex> lock(mutex_);
    queue_.push(ev);
}

bool KeyQueue::pop(KeyEvent& ev) {
    std::lock_guard<std::mutex> lock(mutex_);
    if (queue_.empty()) return false;
    ev = queue_.front();
    queue_.pop();
    return true;
}

void KeyQueue::clear() {
    std::lock_guard<std::mutex> lock(mutex_);
    while (!queue_.empty()) queue_.pop();
}

bool KeyQueue::empty() const {
    std::lock_guard<std::mutex> lock(mutex_);
    return queue_.empty();
}

size_t KeyQueue::size() const {
    std::lock_guard<std::mutex> lock(mutex_);
    return queue_.size();
}
