/*
 * AI generated by GitHub Copilot - DeepSeek V4 Flash
 *
 * Diff two HID reports to find which keys were pressed or released.
 * Pushes individual KeyEvents into the provided queue.
 */
void diff_hid_reports(const unsigned char* old_report,
                      const unsigned char* new_report,
                      KeyQueue& queue) {
    // Modifier byte (byte 0): XOR to find changed modifiers
    uint8_t old_mod = old_report[0];
    uint8_t new_mod = new_report[0];
    uint8_t changed_mod = old_mod ^ new_mod;

    // Report changed modifiers as individual keys
    // Modifier bits: Ctrl=0x01, Shift=0x02, Alt=0x04, GUI=0x08
    static const uint8_t mod_bits[] = {0x01, 0x02, 0x04, 0x08};
    static const uint8_t mod_codes[] = {
        0xE0,  // Left Ctrl
        0xE1,  // Left Shift
        0xE2,  // Left Alt
        0xE3   // Left GUI
    };
    for (int i = 0; i < 4; i++) {
        if (changed_mod & mod_bits[i]) {
            KeyEvent ev;
            ev.modifiers = new_mod;
            ev.keycode = mod_codes[i];
            ev.pressed = (new_mod & mod_bits[i]) != 0;
            queue.push(ev);
        }
    }

    // Keycode bytes (bytes 2..7): find what appeared or disappeared
    // Collect keys currently in old and new reports
    bool old_keys[256] = {false};
    bool new_keys[256] = {false};

    for (int i = 2; i < KEYBOARD_HID_REPORT_SIZE; i++) {
        if (old_report[i] != 0) old_keys[old_report[i]] = true;
        if (new_report[i] != 0) new_keys[new_report[i]] = true;
    }

    // Keys released: present in old but not in new
    for (int i = 2; i < KEYBOARD_HID_REPORT_SIZE; i++) {
        uint8_t k = old_report[i];
        if (k != 0 && !new_keys[k]) {
            KeyEvent ev;
            ev.modifiers = new_mod;
            ev.keycode = k;
            ev.pressed = false;
            queue.push(ev);
        }
    }

    // Keys pressed: present in new but not in old
    for (int i = 2; i < KEYBOARD_HID_REPORT_SIZE; i++) {
        uint8_t k = new_report[i];
        if (k != 0 && !old_keys[k]) {
            KeyEvent ev;
            ev.modifiers = new_mod;
            ev.keycode = k;
            ev.pressed = true;
            queue.push(ev);
        }
    }
}
