/*
 * AI generated by GitHub Copilot - DeepSeek V4 Flash
 *
 * Build a modifier byte from held modifier keys.
 * Modifier keycodes are in range 0xE0-0xE7.
 */
uint8_t modifiers_from_held(const bool held_keys[256]) {
    uint8_t mod = 0;
    if (held_keys[0xE0]) mod |= 0x01;  // Left Ctrl
    if (held_keys[0xE1]) mod |= 0x02;  // Left Shift
    if (held_keys[0xE2]) mod |= 0x04;  // Left Alt
    if (held_keys[0xE3]) mod |= 0x08;  // Left GUI
    if (held_keys[0xE4]) mod |= 0x10;  // Right Ctrl
    if (held_keys[0xE5]) mod |= 0x20;  // Right Shift
    if (held_keys[0xE6]) mod |= 0x40;  // Right Alt
    if (held_keys[0xE7]) mod |= 0x80;  // Right GUI
    return mod;
}
