/*
 * AI generated by GitHub Copilot - DeepSeek V4 Flash
 *
 * Process a queue of KeyEvents into an output HID report.
 * Applies keycode_map remapping.
 *
 * Returns the final report in out_report (8 bytes).
 */
void process_key_queue(KeyQueue& queue,
                       unsigned char* out_report,
                       bool is_grabbed) {
    // Start with empty report
    memset(out_report, 0, KEYBOARD_HID_REPORT_SIZE);

    KeyEvent ev;
    //
    // TODO: In future, intercept and remap keycodes here using
    //       keycode_map before building the output report.
    //       For Italian → German layout simulation, populate
    //       keycode_map with the desired HID code substitutions.
    //

    // Track currently-pressed keys (including modifiers)
    bool held_keys[256] = {false};

    while (queue.pop(ev)) {
        uint8_t mapped = keycode_map[ev.keycode];
        uint8_t effective_key = (mapped != 0) ? mapped : ev.keycode;

        if (ev.pressed) {
            held_keys[effective_key] = true;
        } else {
            held_keys[effective_key] = false;
        }
    }

    // Build output report from held keys
    out_report[0] = modifiers_from_held(held_keys);

    // Write held non-modifier keycodes (up to 6)
    int key_idx = 2;
    for (int h = 4; h < 256; h++) {
        if (held_keys[h]) {
            // Skip modifier keycodes — they go in byte 0
            if (h >= 0xE0 && h <= 0xE7) continue;
            out_report[key_idx++] = static_cast<uint8_t>(h);
            held_keys[h] = false;  // consume
            if (key_idx >= 8) break;
        }
    }
}
